import re

# Current pattern
pattern = re.compile(r'(-|\+|\^|\s+)')

def current_parse(text):
    parts = pattern.split(text)
    if len(parts) == 1:
        return [('key', parts[0])]
    result = []
    while parts:
        key = parts.pop(0)
        result.append(('key', key))
        try:
            sep = parts.pop(0)
            result.append(('sep', sep))
        except IndexError:
            pass
    return result

# Test cases
for case in ['-', '+', '^', 'Shift-+', 'Control+X', 'M-x  M-s', 'space', 'Ctrl++', 'a-b']:
    print(f'{case!r} -> {current_parse(case)}')
